const q = $input.first().json.query || {};
const now = new Date();
return [{ json: {
  clinic_id:    q.clinic_id ? Number(q.clinic_id) : 1,
  period_year:  q.year  ? Number(q.year)  : now.getFullYear(),
  period_month: q.month ? Number(q.month) : now.getMonth() + 1
} }];

const kpis       = $('Dashboard KPIs').first().json;
const topEarners = $('Top Earners').all().map(i => i.json);

const prevGross   = Number(kpis.prev_month_gross || 0);
const totalGross  = Number(kpis.total_gross || 0);
const growthPct   = prevGross > 0 ? Math.round(((totalGross - prevGross) / prevGross) * 100 * 10) / 10 : null;

return [{ json: {
  period: {
    id:     kpis.period_id,
    year:   kpis.period_year,
    month:  kpis.period_month,
    status: kpis.period_status
  },
  kpis: {
    total_gross:         totalGross,
    total_net:           Number(kpis.total_net || 0),
    total_employer_cost: Number(kpis.total_employer_cost || 0),
    entries_count:       Number(kpis.entries_count || 0),
    pending_count:       Number(kpis.pending_count || 0),
    active_employees:    Number(kpis.active_employees || 0),
    active_contracts:    Number(kpis.active_contracts || 0),
    prev_month_gross:    prevGross,
    growth_pct:          growthPct
  },
  top_earners: topEarners
} }];
